	"wms_include_items" "all"
	"wms_exclude_items" "value_0,red,green,blue"
	"force_imagetype" "jpeg"
  END
  CLASS
	NAME "Evapotranspiración Potencial (mm)"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "785 - 1000"
    EXPRESSION ([pixel] >= 785 AND [pixel] < 1000)
    COLOR 176 176 176
  END
  CLASS
	NAME "1000 - 1200"
    EXPRESSION ([pixel] >= 1000 AND [pixel] < 1200)
    COLOR 0 255 0
  END
  CLASS
	NAME "1200 - 1300"
    EXPRESSION ([pixel] >= 1200 AND [pixel] < 1300)
    COLOR 44 89 51
  END
  CLASS
	NAME "1300 - 1400"
    EXPRESSION ([pixel] >= 1300 AND [pixel] < 1400)
    COLOR 66 135 66
  END
  CLASS
	NAME "1400 - 1500"
    EXPRESSION ([pixel] >= 1400 AND [pixel] < 1500)
    COLOR 102 204 119
  END
  CLASS
	NAME "1500 - 1600"
    EXPRESSION ([pixel] >= 1500 AND [pixel] < 1600)
    COLOR 122 245 122
  END
  CLASS
	NAME "1600 - 1700"
    EXPRESSION ([pixel] >= 1600 AND [pixel] < 1700)
    COLOR 208 255 115
  END
  CLASS
	NAME "1700 - 1800"
    EXPRESSION ([pixel] >= 1700 AND [pixel] < 1800)
    COLOR 255 255 115
  END
  CLASS
	NAME "1800 - 1956"
    EXPRESSION ([pixel] >= 1800 AND [pixel] <= 1956)
    COLOR 255 232 128
  END
END # Layer